const payload = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const rawQuery = typeof payload.message === 'string' ? payload.message : payload.query;
const rawProjectSlug = payload.project_slug;
const rawTopK = payload.top_k;
const rawSessionTurns = payload.session_turns;
const buildError = (code, message) => [{ json: { ok: false, error: { code, message }, query: null, project_slug: null, top_k: null, retrieval: { strategy: 'project-first-fallback-general', project_match_count: 0, general_match_count: 0, memory_count: 0, strongest_similarity: null, similarity_threshold: 0.72, empty: true }, context_bundle: null, sources: [], context_preview: '', session: { turn_count_before: 0, history_used: false, stored: false } } }];
if (typeof rawQuery !== 'string' || rawQuery.trim() === '') return buildError('INVALID_INPUT', 'Missing or invalid query/message');
if (rawProjectSlug !== undefined && rawProjectSlug !== null && typeof rawProjectSlug !== 'string') return buildError('INVALID_PROJECT_SLUG', 'project_slug must be a string when provided');
if (rawTopK !== undefined && rawTopK !== null && (!Number.isInteger(rawTopK) || rawTopK < 1 || rawTopK > 8)) return buildError('INVALID_TOP_K', 'top_k must be an integer between 1 and 8');
if (rawSessionTurns !== undefined && !Array.isArray(rawSessionTurns)) return buildError('INVALID_SESSION_TURNS', 'session_turns must be an array when provided');
const sessionTurns = Array.isArray(rawSessionTurns) ? rawSessionTurns.map((turn) => ({ role: turn?.role === 'assistant' ? 'assistant' : 'user', message_text: typeof turn?.message_text === 'string' ? turn.message_text : '', project_slug: typeof turn?.project_slug === 'string' && turn.project_slug.trim() ? turn.project_slug.trim() : null, created_at: typeof turn?.created_at === 'string' ? turn.created_at : null, metadata_json: turn?.metadata_json ?? null })).filter((turn) => turn.message_text) : [];
const projectSlug = typeof rawProjectSlug === 'string' && rawProjectSlug.trim() ? rawProjectSlug.trim() : null;
const recentUserTurns = sessionTurns.filter((turn) => turn.role === 'user').map((turn) => turn.message_text.trim()).filter(Boolean).slice(-2);
const retrievalQuery = projectSlug ? rawQuery.trim() : Array.from(new Set([rawQuery.trim(), ...recentUserTurns])).join('\n');
return [{ json: { request_ok: true, query: rawQuery.trim(), retrieval_query: retrievalQuery, project_slug: projectSlug, top_k: Number.isInteger(rawTopK) ? rawTopK : 5, session_turns: sessionTurns, retrieval_strategy: projectSlug ? 'project-first-fallback-general' : 'general-scope-first-fallback-all', requested_at: new Date().toISOString() } }];

const request = $('Normalize Context Request').first().json;
const statusCode = $json.statusCode ?? 0;
const body = $json.body ?? {};
const embeddings = body.embeddings;
if (statusCode < 200 || statusCode >= 300 || !Array.isArray(embeddings) || !Array.isArray(embeddings[0])) {
  return [{ json: { ...request, embedding_ok: false, error: { code: 'OLLAMA_EMBEDDING_FAILED', message: 'Ollama embedding request failed while building context', status: statusCode || null, details: body.error ?? null } } }];
}
