const base = $('Prepare Retrieval Input').first().json;
const projectMemories = Array.isArray($json.project_memories) ? $json.project_memories : [];
const generalMemories = Array.isArray($json.general_memories) ? $json.general_memories : [];
const selected = [];
const seen = new Set();
const add = (memory) => { if (!memory || seen.has(memory.id) || selected.length >= base.top_k) return; seen.add(memory.id); selected.push(memory); };
if (base.project_slug) { for (const memory of projectMemories) add(memory); for (const memory of generalMemories) add(memory); } else { for (const memory of generalMemories) add(memory); }
const similarityThreshold = 0.72;
const stopTerms = new Set(['what','when','where','which','who','how','this','that','with','from','into','your','about']);
const scoringText = (base.retrieval_query || base.query || '').toLowerCase();
const queryTerms = Array.from(new Set((scoringText.match(/[a-z0-9]{4,}/g) ?? []).filter((term) => !stopTerms.has(term))));
const isUsableContent = (content) => {
  const value = typeof content === 'string' ? content.trim() : '';
  if (value.length < 20) return false;
  if (value.includes('\uFFFD')) return false;
  const alphaCount = (value.match(/[A-Za-z]/g) ?? []).length;
  if (alphaCount < 12) return false;
  const safeCount = (value.match(/[A-Za-z0-9\s.,:;!?()'"_\/-]/g) ?? []).length;
  return safeCount / value.length >= 0.7;
};
const scored = selected.filter((memory) => isUsableContent(memory.content)).map((memory) => {
  const haystack = `${memory.title ?? ''}\n${memory.content ?? ''}`.toLowerCase();
  const lexicalOverlap = queryTerms.filter((term) => haystack.includes(term)).length;
  const similarity = typeof memory.similarity === 'number' ? memory.similarity : 0;
  return { ...memory, lexical_overlap: lexicalOverlap, passes_relevance: similarity >= similarityThreshold || lexicalOverlap >= 1 };
}).sort((a, b) => {
  if (base.project_slug) {
    const ap = a.project_slug === base.project_slug ? 1 : 0;
    const bp = b.project_slug === base.project_slug ? 1 : 0;
    if (bp !== ap) return bp - ap;
  }
  if (b.lexical_overlap !== a.lexical_overlap) return b.lexical_overlap - a.lexical_overlap;
  return (b.similarity ?? 0) - (a.similarity ?? 0);
});
const strong = scored.filter((memory) => memory.passes_relevance).slice(0, base.top_k);
const sessionTurns = Array.isArray(base.session_turns) ? base.session_turns : [];
const sessionHistory = sessionTurns.map((turn) => `${turn.role === 'assistant' ? 'Assistant' : 'User'}: ${turn.message_text}`).join('\n');
