const prompt = [
  'You are CrispyBrain, a local project-aware memory assistant.',
  'Answer using the retrieved memory context only. If memory is incomplete, say so plainly.',
  base.project_slug ? `Requested project_slug: ${base.project_slug}` : null,
  sessionHistory ? `Recent session turns:\n${sessionHistory}` : null,
  context ? `Retrieved memory context:\n${context}` : null,
  `User question:\n${base.query}`,
  'Respond in concise plain text and avoid inventing facts not present in memory.'
].filter(Boolean).join('\n\n');
const sources = strong.map((memory) => ({ id: memory.id, title: memory.title, project_slug: memory.project_slug ?? null, similarity: memory.similarity, lexical_overlap: memory.lexical_overlap, snippet: typeof memory.content === 'string' ? memory.content.slice(0, 180) : '', metadata: memory.metadata_json ?? null }));
const retrieval = { strategy: base.project_slug ? 'project-first-fallback-general' : 'blank-scope-only', project_match_count: projectMemories.length, general_match_count: generalMemories.length, memory_count: strong.length, strongest_similarity: strong.length > 0 ? strong[0].similarity : null, similarity_threshold: similarityThreshold, empty: strong.length === 0 };
return [{ json: { ok: true, query: base.query, project_slug: base.project_slug ?? null, top_k: base.top_k, retrieval, sources, context_preview: context.slice(0, 280), session: { turn_count_before: sessionTurns.length, history_used: sessionTurns.length > 0, stored: false }, context_bundle: { query: base.query, project_slug: base.project_slug ?? null, top_k: base.top_k, requested_at: base.requested_at, retrieval, sources, context, context_preview: context.slice(0, 280), prompt, session: { turn_count_before: sessionTurns.length, history_used: sessionTurns.length > 0, stored: false }, session_turns: sessionTurns, trace: { workflow_chain: ['crispybrain-build-context'], memory_ids: strong.map((memory) => memory.id), query_terms: queryTerms } } } }];
